import {
  serialise, deserialise, canonicalise,
  sha256, sha256Bytes,
  validateMessage,
  MESSAGE_TYPES, PROTOCOL_VERSION,
} from './packages/protocol/dist/index.js';
import crypto from 'crypto';

const uuid = \(\) => crypto.randomUUID\(\);
let pass = 0, fail = 0;
function check\(name, condition, detail\) {
  if \(condition\) { pass++; console.log\('  PASS', name\); }
  else { fail++; console.log\('  FAIL', name, detail || ''\); }
}

console.log\('=== Round-Trip Serialisation Tests ==='\);
console.log\(\);

// -----------------------------------------------------------------------
// Test 1: Task message — full round trip
// -----------------------------------------------------------------------
console.log\('--- Test 1: Task message round trip ---'\);
const taskEnvelope = {
  id: uuid\(\),
  type: 'task',
  timestamp: '2026-03-10T14:30:00.000Z',
  sender: { id: 'harry-001', type: 'human', displayName: 'Harry' },
  correlationId: uuid\(\),
  version: PROTOCOL_VERSION,
  payload: {
    taskId: uuid\(\),
    action: 'restart_nginx',
    target: 'naval-app-01',
    parameters: { graceful: true, timeout: 30 },
    priority: 'high',
    constraints: ['no-downtime', 'backup-first'],
  },
};

const ser1 = serialise\(taskEnvelope\);
check\('serialise produces wire string', typeof ser1.wire === 'string'\);
check\('serialise produces integrity hash', ser1.integrity.startsWith\('sha256:'\)\);
check\('integrity hash is 64 hex chars', ser1.integrity.length === 7 + 64\);
check\('canonical JSON produced', typeof ser1.canonical === 'string'\);

const des1 = deserialise\(ser1.wire\);
check\('deserialise succeeds', des1.success === true\);
if \(des1.success\) {
  check\('envelope.id matches', des1.envelope.id === taskEnvelope.id\);
  check\('envelope.type matches', des1.envelope.type === taskEnvelope.type\);
  check\('envelope.timestamp matches', des1.envelope.timestamp === taskEnvelope.timestamp\);
  check\('payload.action matches', des1.envelope.payload.action === 'restart_nginx'\);
  check\('payload.priority matches', des1.envelope.payload.priority === 'high'\);
  check\('payload.constraints length', des1.envelope.payload.constraints.length === 2\);
  check\('integrity matches', des1.integrity === ser1.integrity\);
  check\('canonical matches', des1.canonical === ser1.canonical\);
}
console.log\(\);

// -----------------------------------------------------------------------
// Test 2: Challenge message — round trip with nested objects
// -----------------------------------------------------------------------
console.log\('--- Test 2: Challenge message round trip ---'\);
const challengeEnvelope = {
  id: uuid\(\),
  type: 'challenge',
  timestamp: '2026-03-10T02:15:00.000Z',
  sender: { id: 'claude-001', type: 'ai', displayName: 'Claude' },
  correlationId: uuid\(\),
  version: PROTOCOL_VERSION,
  payload: {
    challengedMessageId: uuid\(\),
    challengedTaskId: uuid\(\),
    layer: 2,
    reason: 'Task submitted during high-risk hours \(02:15 UTC\)',
    riskAssessment: 'Elevated risk: service restart at 2am',
    suggestedAlternatives: ['Schedule for 09:00', 'Use graceful reload'],
    factors: [
      { name: 'time_of_day', description: 'High-risk window', weight: 0.7 },
      { name: 'reversibility', description: 'Reversible op', weight: 0.2 },
    ],
  },
};

const ser2 = serialise\(challengeEnvelope\);
const des2 = deserialise\(ser2.wire\);
check\('challenge round trip succeeds', des2.success === true\);
if \(des2.success\) {
  check\('factors preserved', des2.envelope.payload.factors.length === 2\);
  check\('factor weight preserved', des2.envelope.payload.factors[0].weight === 0.7\);
  check\('alternatives preserved', des2.envelope.payload.suggestedAlternatives.length === 2\);
}
console.log\(\);

// -----------------------------------------------------------------------
// Test 3: Heartbeat — edge case: zero/boundary metrics
// -----------------------------------------------------------------------
console.log\('--- Test 3: Heartbeat with zero metrics ---'\);
const heartbeatEnvelope = {
  id: uuid\(\),
  type: 'heartbeat',
  timestamp: '2026-03-10T14:33:00.000Z',
  sender: { id: 'claude-001', type: 'ai', displayName: 'Claude' },
  correlationId: uuid\(\),
  version: PROTOCOL_VERSION,
  payload: {
    sessionId: uuid\(\),
    peerStatus: 'active',
    metrics: { uptimeMs: 0, memoryUsageMb: 0, cpuPercent: 0, latencyMs: 0 },
  },
};

const ser3 = serialise\(heartbeatEnvelope\);
const des3 = deserialise\(ser3.wire\);
check\('heartbeat round trip', des3.success === true\);
if \(des3.success\) {
  check\('zero uptimeMs preserved', des3.envelope.payload.metrics.uptimeMs === 0\);
  check\('zero cpuPercent preserved', des3.envelope.payload.metrics.cpuPercent === 0\);
}
console.log\(\);

// -----------------------------------------------------------------------
// Test 4: Integrity tamper detection
// -----------------------------------------------------------------------
console.log\('--- Test 4: Tamper detection ---'\);

// 4a: Modify payload in wire data
const tampered = ser1.wire.replace\('restart_nginx', 'rm_rf_slash'\);
const des4a = deserialise\(tampered\);
check\('tampered payload detected', des4a.success === false\);
if \(!des4a.success\) {
  check\('reports hash mismatch', des4a.errors.some\(e => e.message.includes\('hash does not match'\)\)\);
}

// 4b: Modify integrity hash directly
const parsed = JSON.parse\(ser1.wire\);
parsed._integrity = 'sha256:' + '0'.repeat\(64\);
const des4b = deserialise\(JSON.stringify\(parsed\)\);
check\('forged hash detected', des4b.success === false\);

// 4c: Remove integrity field entirely
delete parsed._integrity;
const des4c = deserialise\(JSON.stringify\(parsed\)\);
check\('missing integrity detected', des4c.success === false\);
if \(!des4c.success\) {
  check\('reports missing _integrity', des4c.errors.some\(e => e.path === '_integrity'\)\);
}
console.log\(\);

// -----------------------------------------------------------------------
// Test 5: Invalid JSON
// -----------------------------------------------------------------------
console.log\('--- Test 5: Bad input handling ---'\);
const des5a = deserialise\('not json at all'\);
check\('invalid JSON rejected', des5a.success === false\);

const des5b = deserialise\('42'\);
check\('non-object JSON rejected', des5b.success === false\);

const des5c = deserialise\('null'\);
check\('null rejected', des5c.success === false\);

const des5d = deserialise\('[1,2,3]'\);
check\('array rejected', des5d.success === false\);
console.log\(\);

// -----------------------------------------------------------------------
// Test 6: Serialise rejects invalid envelopes
// -----------------------------------------------------------------------
console.log\('--- Test 6: Serialise validation ---'\);
try {
  serialise\({ id: 'bad', type: 'task', timestamp: 'not-iso', sender: {}, correlationId: 'bad', version: '', payload: {} }\);
  check\('invalid envelope throws', false\);
} catch \(err\) {
  check\('invalid envelope throws SerialisationError', err.name === 'SerialisationError'\);
  check\('error has .errors array', Array.isArray\(err.errors\) && err.errors.length > 0\);
}
console.log\(\);

// -----------------------------------------------------------------------
// Test 7: Canonical JSON determinism
// -----------------------------------------------------------------------
console.log\('--- Test 7: Canonical JSON determinism ---'\);
const objA = { z: 1, a: 2, m: { b: 3, a: 4 } };
const objB = { a: 2, m: { a: 4, b: 3 }, z: 1 };
check\('different key order → same canonical', canonicalise\(objA\) === canonicalise\(objB\)\);
check\('canonical has sorted keys', canonicalise\(objA\) === '{\\"a\\":2,\\"m\\":{\\"a\\":4,\\"b\\":3},\\"z\\":1}'\);

// Verify same envelope serialised twice produces identical hashes
const ser7a = serialise\(taskEnvelope\);
const ser7b = serialise\(taskEnvelope\);
check\('same envelope → same integrity', ser7a.integrity === ser7b.integrity\);
check\('same envelope → same canonical', ser7a.canonical === ser7b.canonical\);
console.log\(\);

// -----------------------------------------------------------------------
// Test 8: SHA-256 utility direct verification
// -----------------------------------------------------------------------
console.log\('--- Test 8: SHA-256 verification ---'\);
const knownInput = 'hello';
const knownHash = crypto.createHash\('sha256'\).update\('hello'\).digest\('hex'\);
check\('sha256\(\\"hello\\"\) matches Node crypto', sha256\('hello'\) === knownHash\);

const bytes = sha256Bytes\('hello'\);
check\('sha256Bytes returns 32 bytes', bytes.length === 32\);
check\('sha256Bytes matches hex', Buffer.from\(bytes\).toString\('hex'\) === knownHash\);
console.log\(\);

// -----------------------------------------------------------------------
// Test 9: Budget alert — supplementary type round trip
// -----------------------------------------------------------------------
console.log\('--- Test 9: Budget alert round trip ---'\);
const budgetEnvelope = {
  id: uuid\(\),
  type: 'budget_alert',
  timestamp: '2026-03-10T23:59:59.000Z',
  sender: { id: 'claude-001', type: 'ai', displayName: 'Claude' },
  correlationId: uuid\(\),
  version: PROTOCOL_VERSION,
  payload: {
    thresholdPercent: 90,
    usedAmountUsd: 4.50,
    budgetLimitUsd: 5.00,
    currentPeriod: '2026-03',
    estimatedCostForNextTask: 0.12,
  },
};

const ser9 = serialise\(budgetEnvelope\);
const des9 = deserialise\(ser9.wire\);
check\('budget alert round trip', des9.success === true\);
if \(des9.success\) {
  check\('float preserved \(4.50\)', des9.envelope.payload.usedAmountUsd === 4.5\);
  check\('optional field preserved', des9.envelope.payload.estimatedCostForNextTask === 0.12\);
}
console.log\(\);

// -----------------------------------------------------------------------
// Summary
// -----------------------------------------------------------------------
console.log\('================================================='\);
console.log\('Results:', pass, 'passed,', fail, 'failed'\);
console.log\('================================================='\);
if \(fail > 0\) process.exit\(1\);
" 2>&1)
